import React, { useState } from 'react';

export default function Clientes({ clientes }) {
  const [busqueda, setBusqueda] = useState('');
  const filtrados = clientes.filter(c => c.nombre.toLowerCase().includes(busqueda.toLowerCase()));

  return (
    <div style={{ padding:'1.5rem' }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'1.25rem' }}>
        <h1 style={{ fontSize:20, fontWeight:700 }}>Clientes</h1>
        <input value={busqueda} onChange={e=>setBusqueda(e.target.value)}
          placeholder="Buscar cliente..."
          style={{ padding:'8px 12px', borderRadius:8, border:'1px solid #E2E8F0', fontSize:14, width:220, outline:'none' }} />
      </div>
      <div style={{ background:'#fff', borderRadius:12, overflow:'hidden' }}>
        <table style={{ width:'100%', borderCollapse:'collapse' }}>
          <thead>
            <tr style={{ background:'#F8FAFC' }}>
              {['Cliente','Teléfono','Dirección','Pedidos','Último pedido','Total gastado'].map(h=>(
                <th key={h} style={{ padding:'10px 14px', textAlign:'left', fontSize:12, color:'#64748B', fontWeight:600, borderBottom:'1px solid #F1F5F9' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtrados.map(c=>(
              <tr key={c.id} style={{ borderBottom:'1px solid #F8FAFC' }}>
                <td style={{ padding:'12px 14px' }}>
                  <div style={{ display:'flex', alignItems:'center', gap:10 }}>
                    <div style={{ width:34, height:34, borderRadius:'50%', background:'#EFF6FF', display:'flex', alignItems:'center', justifyContent:'center', fontSize:13, fontWeight:700, color:'#2563EB' }}>
                      {c.nombre.split(' ').map(n=>n[0]).join('').slice(0,2)}
                    </div>
                    <span style={{ fontSize:14, fontWeight:500 }}>{c.nombre}</span>
                  </div>
                </td>
                <td style={{ padding:'12px 14px', fontSize:13, color:'#64748B' }}>{c.telefono}</td>
                <td style={{ padding:'12px 14px', fontSize:13, color:'#64748B' }}>{c.direccion}</td>
                <td style={{ padding:'12px 14px', fontSize:13, fontWeight:600, textAlign:'center' }}>{c.pedidos}</td>
                <td style={{ padding:'12px 14px', fontSize:13, color:'#64748B' }}>{c.ultimo}</td>
                <td style={{ padding:'12px 14px', fontSize:13, fontWeight:600, color:'#10B981' }}>Bs. {c.gasto}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
